.darma-loader-darma-custom-003 {
  width: 40px;
  aspect-ratio: 1;
  background: linear-gradient(45deg, var(--loader-color, #00AAFF) 50%, #0000 0), linear-gradient(-45deg, #F1BBBB 50%, #0000 0), linear-gradient(45deg, #0000 50%, #AA00FF 0), linear-gradient(-45deg, #0000 50%, var(--loader-secondary-color, #FF00AA) 0), var(--loader-color, #00AAFF);
  background-size: 200% 200%;
  background-repeat: no-repeat;
  animation: darma-loader-darma-custom-003-l3 2.5s infinite;
}
@keyframes darma-loader-darma-custom-003-l3 {
  0% { background-position: 100% 0, 0 0, 0 100%, 100% 100%; }
  15%, 25% { background-position: 100% 0, 0 0, 0 100%, 0 0; }
  40%, 50% { background-position: 100% 0, 0 0, 100% 0, 0 0; }
  65%, 75% { background-position: 100% 0, 100% 100%, 100% 0, 0 0; }
  90%, 100% { background-position: 0 100%, 100% 100%, 100% 0, 0 0; }
}

